import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom";
import Login from "./pages/Login";
import Police from "./pages/Police";
import Hospital from "./pages/Hospital";
import Admin from "./pages/Admin";

// ── Leaflet icon fix (centralized here — do NOT repeat in other components) ──
import L from "leaflet";
delete L.Icon.Default.prototype._getIconUrl;
L.Icon.Default.mergeOptions({
  iconRetinaUrl: require("leaflet/dist/images/marker-icon-2x.png"),
  iconUrl:       require("leaflet/dist/images/marker-icon.png"),
  shadowUrl:     require("leaflet/dist/images/marker-shadow.png"),
});

// ── Simple role-based route guard ─────────────────────────────────────────────
// Reads the role saved to localStorage after login.
// Usage: <ProtectedRoute role="admin"> wraps <Admin/>
function ProtectedRoute({ role, children }) {
  const savedRole = localStorage.getItem("role");

  if (!savedRole) {
    // Not logged in → back to login
    return <Navigate to="/" replace />;
  }

  if (role && savedRole !== role) {
    // Wrong role → redirect to their correct dashboard
    const dashboards = {
      admin:    "/admin",
      police:   "/police",
      hospital: "/hospital",
    };
    return <Navigate to={dashboards[savedRole] || "/"} replace />;
  }

  return children;
}

function App() {
  return (
    <BrowserRouter>
      <Routes>
        {/* Public */}
        <Route path="/" element={<Login />} />

        {/* Protected dashboards */}
        <Route
          path="/admin"
          element={
            <ProtectedRoute role="admin">
              <Admin />
            </ProtectedRoute>
          }
        />
        <Route
          path="/police"
          element={
            <ProtectedRoute role="police">
              <Police />
            </ProtectedRoute>
          }
        />
        <Route
          path="/hospital"
          element={
            <ProtectedRoute role="hospital">
              <Hospital />
            </ProtectedRoute>
          }
        />

        {/* Catch-all → login */}
        <Route path="*" element={<Navigate to="/" replace />} />
      </Routes>
    </BrowserRouter>
  );
}

export default App;
